create table dirkspzm32.rep_abfragen (
    rep_id                 number(*, 0) not null enable,
    rep_name               varchar2(100 char) not null enable,
    rep_gruppe             varchar2(100 char) not null enable,
    rep_info               varchar2(255 char),
    rep_intern             varchar2(10 char) default 'F' not null enable,
    sort_field_param_name  varchar2(50 char),
    erz_datum              date not null enable,
    erz_login_name         varchar2(50 char) not null enable,
    aend_datum             date,
    aend_login_name        varchar2(50 char),
    rave_rep_datei         varchar2(255 char),
    rave_rep_name          varchar2(255 char),
    default_sort_field     varchar2(100 char),
    security_level         number(*, 0) default 30 not null enable,
    mod_id                 number(*, 0),
    rep_sql_clob           clob,
    web_freigabe           varchar2(1 char) default 'F' not null enable,
    default_anzeige        varchar2(10 char) default 'T' not null enable,
    sid                    varchar2(2 char) default '01' not null enable,
    firma_nr               number(6, 0) default 1 not null enable,
    chart_anzeige_aktiv    varchar2(1 char) default 'F' not null enable,
    extensions_params_csv  varchar2(2000 char),
    base_rep_name          varchar2(100 char),
    rep_ext_db_name        varchar2(50 char),
    detail_rep_name        varchar2(100 char),
    rep_caption            varchar2(255 char),
    dlg_short_name         varchar2(50 char),
    custom_code            varchar2(10 char),
    dlg_category           number(*, 0),
    master_category        number(*, 0),
    show_type              number(*, 0),
    embed_in_menu          varchar2(1 char),
    show_in_toolbar        varchar2(1 char),
    enabled_extensions_csv varchar2(255 char),
    icon16_ix              number(*, 0) default - 1 not null enable,
    icon32_ix              number(*, 0) default - 1 not null enable,
    show_detail_data       varchar2(1 char) default 'F' not null enable,
    query_type             varchar2(10 char) default 'select' not null enable,
    sorting_mode           varchar2(10 char) default 'SQL' not null enable
);

alter table dirkspzm32.rep_abfragen
    add constraint pk_rep_id primary key ( rep_id )
        using index enable;

alter table dirkspzm32.rep_abfragen
    add constraint uix_rep_name_gruppe unique ( rep_name,
                                                rep_gruppe )
        using index enable;


